        vector<int> lh(n, INT_MAX), hl(n, INT_MAX), ans(n, INT_MAX);
        
        unordered_map<int, int> mp;
        for (int i = 0; i < 2 * n - 1; i++) {
            int idx = i % n;
            if (mp.find(nums[idx]) == mp.end()) {
                mp[nums[idx]] = i;
            } else {
                lh[idx] = min(lh[idx], abs(i - mp[nums[idx]]));
                mp[nums[idx]] = i;
            }
        }
        unordered_map<int, int> mp2;
        for (int i = n - 1; i > -n; i--) {
            int idx = (i + n) % n;
            if (mp2.find(nums[idx]) == mp2.end()) {
                mp2[nums[idx]] = i;
            } else {
                hl[idx] = min(hl[idx], abs(i - mp2[nums[idx]]));
                mp2[nums[idx]] = i;
            }
        }
        for (int i = 0; i < n; i++) {
            ans[i] = min(lh[i], hl[i]);
        }
        vector<int> result;
        for (int q : queries) {
            if (q < 0 || q >= n || ans[q] == INT_MAX || ans[q] == nums.size()) {
                result.push_back(-1);
            } else {
                result.push_back(ans[q]);
            }
        }
        
        return result;
    }
